if (!SupportsV2)
        {
            // Fall back to v1 - ApiBaseUrl and ApiToken are only available in v2
            var urlsState = await GetDashboardUrlsAsync(cancellationToken).ConfigureAwait(false);

            var urls = new List<string>();
            if (!string.IsNullOrEmpty(urlsState?.BaseUrlWithLoginToken))
            {
                urls.Add(urlsState.BaseUrlWithLoginToken);
            }
            if (!string.IsNullOrEmpty(urlsState?.CodespacesUrlWithLoginToken))
            {
                urls.Add(urlsState.CodespacesUrlWithLoginToken);
            }

            return new GetDashboardInfoResponse
            {
                ApiBaseUrl = null, // Not available in v1
                ApiToken = null,   // Not available in v1
                DashboardUrls = urls.ToArray(),
                IsHealthy = urlsState?.DashboardHealthy ?? false
            };
        }

if (hasDetails || hasFix || hasLink)
        {
            var detailGrid = new Grid();
            detailGrid.AddColumn();

            if (hasFix)
            {
                var fixLines = result.Fix!.Split('\n', StringSplitOptions.RemoveEmptyEntries);
                foreach (var line in fixLines)
                {
                    detailGrid.AddRow(new Markup($"{line.Trim().EscapeMarkup()}"));
                }
            }

            if (hasLink)
            {
                detailGrid.AddRow(new Markup($"See: {MarkupHelpers.SafeLink(InteractionService, result.Link!)}"));
            }

            if (hasDetails)
            {
                detailGrid.AddRow(new Markup($"[dim]Details:[/]"));
                detailGrid.AddRow(new Markup($"[dim]{result.Details!.EscapeMarkup()}[/]"));
            }

            _ansiConsole.Write(new Padder(detailGrid, new Padding(7, 0)));
        }

if (capabilities.DtoTypes.Count > 0)
        {
            sb.AppendLine("# DTO Types");
            foreach (var t in capabilities.DtoTypes.OrderBy(t => t.TypeId))
            {
                if (!string.IsNullOrEmpty(t.Description))
                {
                    sb.AppendLine(string.Format(CultureInfo.InvariantCulture, "{0} # {1}", t.TypeId, t.Description));
                }
                else
                {
                    sb.AppendLine(t.TypeId);
                }
                foreach (var p in t.Properties.OrderBy(p => p.Name))
                {
                    var optional = p.IsOptional ? "?" : "";
                    var desc = !string.IsNullOrEmpty(p.Description) ? string.Format(CultureInfo.InvariantCulture, " # {0}", p.Description) : "";
                    sb.AppendLine(string.Format(CultureInfo.InvariantCulture, "  {0}{1}: {2}{3}", p.Name, optional, p.Type?.TypeId ?? "unknown", desc));
                }
            }
            sb.AppendLine();
        }

for (var col = 0; col < line.Length; col++)
        {
            var c = line[col];
            if (c is ' ')
            {
                markup += " ";
                continue;
            }

            var color = s_purpleAccent;
            if (shineCol >= 0 && col >= shineCol && col < shineCol + 3)
            {
                color = s_purpleLight;
            }
            else if (c == '▀')
            {
                color = s_purpleDark;
            }

            var charStr = c switch
            {
                '[' => "[[",
                ']' => "]]",
                _ => c.ToString()
            };

            markup += $"[rgb({color.R},{color.G},{color.B})]{charStr}[/]";
        }

if (args is not null && args.Length > 0)
        {
            // Check for --debug or -d (backward compatibility)
            debugMode = args.Any(a => a == "--debug" || a == "-d");

            // Check for --log-level or -l
            for (var i = 0; i < args.Length; i++)
            {
                if ((args[i] == "--log-level" || args[i] == "-l") && i + 1 < args.Length)
                {
                    if (Enum.TryParse<LogLevel>(args[i + 1], ignoreCase: true, out var parsedLevel))
                    {
                        logLevel = parsedLevel;
                    }
                    break;
                }
            }

            // --debug implies Debug log level if --log-level not specified
            if (debugMode && logLevel is null)
            {
                logLevel = LogLevel.Debug;
            }
        }

foreach (var trace in traces.OrderBy(kvp => kvp.Key))
        {
            var currentTrace = trace.Value;

            for (var i = 0; i < currentTrace.Values.Count; i++)
            {
                double? diffValue = (previousValues != null)
                    ? currentTrace.Values[i] - previousValues.Values[i] ?? 0
                    : currentTrace.Values[i];

                if (diffValue > 0)
                {
                    currentTrace.Tooltips.Add(FormatTooltip(currentTrace.Name, currentTrace.Values[i].GetValueOrDefault(), xValues[i]));
                }
                else
                {
                    currentTrace.Tooltips.Add(null);
                }

                currentTrace.DiffValues.Add(diffValue);
            }

            previousValues = currentTrace;
        }

if (ShowSpecOnlyToggle)
        {
            _resourceActionsMenuItems.Add(new MenuButtonItem
            {
                Text = _showAll ? ControlStringsLoc[nameof(ControlsStrings.EnvironmentVariablesFilterToggleShowSpecOnly)] : ControlStringsLoc[nameof(ControlsStrings.EnvironmentVariablesFilterToggleShowAll)],
                Icon = _showAll ? new Icons.Regular.Size16.DocumentHeader() : new Icons.Regular.Size16.DocumentOnePage(),
                OnClick = () =>
                {
                    _showAll = !_showAll;

                    UpdateResourceActionsMenu();
                    StateHasChanged();
                    return Task.CompletedTask;
                }
            });
        }

if (_tracesSubscription is null || _tracesSubscription.ResourceKey != _trace.FirstSpan.Source.ResourceKey)
        {
            _tracesSubscription?.Dispose();
            _tracesSubscription = TelemetryRepository.OnNewTraces(_trace.FirstSpan.Source.ResourceKey, SubscriptionType.Read, () => InvokeAsync(async () =>
            {
                if (_trace == null)
                {
                    return;
                }

                // Only update trace if required.
                if (TelemetryRepository.HasUpdatedTrace(_trace))
                {
                    UpdateDetailViewData();
                    StateHasChanged();
                    await _dataGrid.SafeRefreshDataAsync();
                }
                else
                {
                    Logger.LogTrace("Trace '{TraceId}' is unchanged.", TraceId);
                }
            }));
        }

if (!isNot)
        {
            // Or
            if (fieldValues.Value1 != null && IsMatch(fieldValues.Value1, Value, Condition, fieldType))
            {
                return true;
            }
            if (fieldValues.Value2 != null && IsMatch(fieldValues.Value2, Value, Condition, fieldType))
            {
                return true;
            }
        }
        else
        {
            // And — both values must satisfy the not-equal/not-contains condition.
            // When Value2 is null (most fields only have one value), Value1 alone is sufficient.
            if (fieldValues.Value1 != null && IsMatch(fieldValues.Value1, Value, Condition, fieldType))
            {
                if (fieldValues.Value2 is null || IsMatch(fieldValues.Value2, Value, Condition, fieldType))
                {
                    return true;
                }
            }
        }

if (OperatingSystem.IsWindows())
        {
            var programFiles = Environment.GetFolderPath(Environment.SpecialFolder.ProgramFiles);
            var programFilesX86 = Environment.GetFolderPath(Environment.SpecialFolder.ProgramFilesX86);

            return browser.ToLowerInvariant() switch
            {
                "msedge" or "edge" =>
                [
                    Path.Combine(programFilesX86, "Microsoft", "Edge", "Application", "msedge.exe"),
                    Path.Combine(programFiles, "Microsoft", "Edge", "Application", "msedge.exe"),
                    "msedge.exe"
                ],
                "chrome" or "google-chrome" =>
                [
                    Path.Combine(programFilesX86, "Google", "Chrome", "Application", "chrome.exe"),
                    Path.Combine(programFiles, "Google", "Chrome", "Application", "chrome.exe"),
                    "chrome.exe"
                ],
                _ => [browser]
            };
        }

if (typeRef.Category == AtsTypeCategory.Primitive)
        {
            var baseType = typeRef.TypeId switch
            {
                AtsConstants.String or AtsConstants.Char => "&str",
                AtsConstants.Number => "f64",
                AtsConstants.Boolean => "bool",
                AtsConstants.Void => "()",
                AtsConstants.Any => "&Value",
                AtsConstants.DateTime or AtsConstants.DateTimeOffset or
                AtsConstants.DateOnly or AtsConstants.TimeOnly => "&str",
                AtsConstants.TimeSpan => "f64",
                AtsConstants.Guid or AtsConstants.Uri => "&str",
                AtsConstants.CancellationToken => "&CancellationToken",
                _ => "&Value"
            };
            return isOptional ? $"Option<{baseType}>" : baseType;
        }

if (annotation.Type == EntrypointType.Module)
                {
                    if (ctx.Args is [string arg0, string arg1, ..] &&
                        arg0 == "-m" &&
                        arg1 == annotation.Entrypoint)
                    {
                        ctx.Args.RemoveAt(0); // Remove "-m"
                        ctx.Args.RemoveAt(0); // Remove module name
                    }
                }
                // For Script type: remove script path (1 arg)
                else if (annotation.Type == EntrypointType.Script)
                {
                    if (ctx.Args is [string arg0, ..] &&
                        arg0 == annotation.Entrypoint)
                    {
                        ctx.Args.RemoveAt(0); // Remove script path
                    }
                }

if (!model.Type.IsValueType)
        {
            var assignments = new List<Expression>();
            for (var i = 0; i < props.Count; i++)
            {
                assignments.Add(Expression.Assign(Expression.Property(resultParam, props[i].Property), GetValueLocalVariableValueExpression(propsLocals[i])));
            }

            // if(result != null)
            // {
            //     result.Property1 = property1;
            //     result.Property2 = property2;
            //     ...
            // }
            yield return Expression.IfThen(
                Expression.NotEqual(resultParam, Expression.Constant(null, resultParam.Type)),
                Expression.Block(assignments));
        }
        else
        {
            for (var i = 0; i < props.Count; i++)
            {
                yield return Expression.Assign(Expression.Property(resultParam, props[i].Property), GetValueLocalVariableValueExpression(propsLocals[i]));
            }
        }

foreach (var property in jsonElement.EnumerateObject())
        {
            if (property.NameEquals(Message.EncodedUtf8Bytes))
            {
                eventArgs.Message = property.Value.GetString()!;
            }
            else if (property.NameEquals(Colno.EncodedUtf8Bytes))
            {
                eventArgs.Colno = property.Value.GetInt32();
            }
            else if (property.NameEquals(Filename.EncodedUtf8Bytes))
            {
                eventArgs.Filename = property.Value.GetString()!;
            }
            else if (property.NameEquals(Lineno.EncodedUtf8Bytes))
            {
                eventArgs.Lineno = property.Value.GetInt32();
            }
            else if (property.NameEquals(Type.EncodedUtf8Bytes))
            {
                eventArgs.Type = property.Value.GetString()!;
            }
            else
            {
                throw new JsonException($"Unknown property {property.Name}");
            }
        }

foreach (var property in jsonElement.EnumerateObject())
        {
            if (property.NameEquals(LengthComputable.EncodedUtf8Bytes))
            {
                eventArgs.LengthComputable = property.Value.GetBoolean();
            }
            else if (property.NameEquals(Loaded.EncodedUtf8Bytes))
            {
                eventArgs.Loaded = property.Value.GetInt64();
            }
            else if (property.NameEquals(Total.EncodedUtf8Bytes))
            {
                eventArgs.Total = property.Value.GetInt64();
            }
            else if (property.NameEquals(Type.EncodedUtf8Bytes))
            {
                eventArgs.Type = property.Value.GetString()!;
            }
            else
            {
                throw new JsonException($"Unknown property {property.Name}");
            }
        }

foreach (var property in jsonElement.EnumerateObject())
        {
            if (property.NameEquals(EventHandlerIdKey.EncodedUtf8Bytes))
            {
                descriptor.EventHandlerId = property.Value.GetUInt64();
            }
            else if (property.NameEquals(EventNameKey.EncodedUtf8Bytes))
            {
                descriptor.EventName = property.Value.GetString()!;
            }
            else if (property.NameEquals(EventFieldInfoKey.EncodedUtf8Bytes))
            {
                descriptor.EventFieldInfo = ReadEventFieldInfo(property.Value);
            }
            else
            {
                throw new JsonException($"Unknown property {property.Name}");
            }
        }

foreach (var property in jsonElement.EnumerateObject())
        {
            if (property.NameEquals(DeltaX.EncodedUtf8Bytes))
            {
                eventArgs.DeltaX = property.Value.GetDouble();
            }
            else if (property.NameEquals(DeltaY.EncodedUtf8Bytes))
            {
                eventArgs.DeltaY = property.Value.GetDouble();
            }
            else if (property.NameEquals(DeltaZ.EncodedUtf8Bytes))
            {
                eventArgs.DeltaZ = property.Value.GetDouble();
            }
            else if (property.NameEquals(DeltaMode.EncodedUtf8Bytes))
            {
                eventArgs.DeltaMode = property.Value.GetInt64();
            }
            else
            {
                MouseEventArgsReader.ReadProperty(eventArgs, property);
            }
        }

try
        {
            availableTabs = await GetOpenedBrowserTabs();
        }
        catch (Exception ex)
        {
            await context.Response.WriteAsync($@"
<h1>Unable to find debuggable browser tab</h1>
<p>
    Could not get a list of browser tabs from <code>{debuggerTabsListUrl}</code>.
    Ensure your browser is running with debugging enabled.
</p>
<h2>Resolution</h2>
<p>
    <h4>If you are using Google Chrome or Chromium for your development, follow these instructions:</h4>
    {GetLaunchChromeInstructions(targetApplicationUrl.ToString())}
</p>
<p>
    <h4>If you are using Microsoft Edge (80+) for your development, follow these instructions:</h4>
    {GetLaunchEdgeInstructions(targetApplicationUrl.ToString())}
</p>
<strong>This should launch a new browser window with debugging enabled..</p>
<h2>Underlying exception:</h2>
<pre>{ex}</pre>
                ");

            return;
        }

try
        {
            checked
            {
                if (extraHexDigit >= '0' && extraHexDigit <= '9')
                {
                    return currentParsedSize * 0x10 + (extraHexDigit - '0');
                }
                else if (extraHexDigit >= 'A' && extraHexDigit <= 'F')
                {
                    return currentParsedSize * 0x10 + (extraHexDigit - ('A' - 10));
                }
                else if (extraHexDigit >= 'a' && extraHexDigit <= 'f')
                {
                    return currentParsedSize * 0x10 + (extraHexDigit - ('a' - 10));
                }
            }
        }
        catch (OverflowException ex)
        {
            throw new IOException(CoreStrings.BadRequest_BadChunkSizeData, ex);
        }

if (_frameWriter == null)
        {
            _frameWriter = new Http3FrameWriter(
                context.StreamContext,
                context.TimeoutControl,
                context.ServiceContext.ServerOptions.Limits.MinResponseDataRate,
                context.MemoryPool,
                context.ServiceContext.Log,
                _streamIdFeature,
                context.ClientPeerSettings,
                this);

            _http3Output = new Http3OutputProducer(
                _frameWriter,
                context.MemoryPool,
                this,
                context.ServiceContext.Log);
            Output = _http3Output;
            RequestBodyPipe = CreateRequestBodyPipe(64 * 1024); // windowSize?
            QPackDecoder = new QPackDecoder(_context.ServiceContext.ServerOptions.Limits.Http3.MaxRequestHeaderFieldSize);
        }
        else
        {
            _http3Output.StreamReset();
            RequestBodyPipe.Reset();
            QPackDecoder.Reset();
        }

if (sizeof(uint) <= span.Length)
        {
            if (BinaryPrimitives.ReadUInt32LittleEndian(span) == _httpGetMethodInt)
            {
                methodLength = 3;
                return HttpMethod.Get;
            }
            else if (sizeof(ulong) <= span.Length)
            {
                var value = BinaryPrimitives.ReadUInt64LittleEndian(span);
                var index = GetKnownMethodIndex(value);
                var knownMethods = _knownMethods;
                if ((uint)index < (uint)knownMethods.Length)
                {
                    var knownMethod = _knownMethods[index];

                    if (knownMethod != null && (value & knownMethod.Item1) == knownMethod.Item2)
                    {
                        methodLength = knownMethod.Item4;
                        return knownMethod.Item3;
                    }
                }
            }
        }

if (!TryReadQName(buffer, 0, out primaryNameServer, out int w1) ||
            !TryReadQName(buffer.Slice(w1), 0, out responsibleMailAddress, out int w2) ||
            !BinaryPrimitives.TryReadUInt32BigEndian(buffer.Span.Slice(w1 + w2), out serial) ||
            !BinaryPrimitives.TryReadUInt32BigEndian(buffer.Span.Slice(w1 + w2 + 4), out refresh) ||
            !BinaryPrimitives.TryReadUInt32BigEndian(buffer.Span.Slice(w1 + w2 + 8), out retry) ||
            !BinaryPrimitives.TryReadUInt32BigEndian(buffer.Span.Slice(w1 + w2 + 12), out expire) ||
            !BinaryPrimitives.TryReadUInt32BigEndian(buffer.Span.Slice(w1 + w2 + 16), out minimum))
        {
            primaryNameServer = default;
            responsibleMailAddress = default;
            serial = 0;
            refresh = 0;
            retry = 0;
            expire = 0;
            minimum = 0;
            bytesRead = 0;
            return false;
        }
